let allContractsData = [...categoriesData, ...commercialContracts, ...laborContracts];

// Will continue with more categories in subsequent batches
let output = '';
let contractCounter = 0;

for (const catGroup of allContractsData) {
  for (const c of catGroup.contracts) {
    contractCounter++;
    const slug = `contract-${catGroup.category}-${slugify(c.title.replace(/'/g, ''))}-${contractCounter}`;
    const content = contractContent(c.title);
    const summary = `این قرارداد ${c.title} یک سند حقوقی ${c.difficulty === 'GENERAL' ? 'عمومی و قابل استفاده برای عموم مردم' : c.difficulty === 'SPECIALIZED' ? 'تخصصی و مناسب برای متخصصان و صاحبان کسب‌وکار' : 'پیشرفته و مناسب برای موارد پیچیده حقوقی'} است که شامل کلیه شرایط، تعهدات و حقوق طرفین می‌باشد.`;
    const tagsStr = c.tags.map(t => `'${t}'`).join(', ');
    const lawsStr = c.laws.map(l => `'${l}'`).join(', ');

    output += `  {
    title: '${c.title}',
    slug: '${slug}',
    description: '${c.title} - قرارداد حقوقی با شرایط و تعهدات مشخص',
    content: ${JSON.stringify(content)},
    summary: '${summary}',
    categorySlug: '${catGroup.category}',
    tags: [${tagsStr}],
    applicableLaws: [${lawsStr}],
    difficulty: '${c.difficulty}',
  },\n`;
  }
}

fs.appendFileSync('seed-output.ts', output);
console.log(`Generated ${contractCounter} contracts so far`);
console.log(`Output size: ${output.length} bytes`);
